SELECT ao.opinion_id, ao.selection_id, ao.doc_id, ao.doc_type, CASE ao.doc_type WHEN 'PROPOSAL' THEN '开题报告' WHEN 'MIDTERM' THEN '中期检查' WHEN 'THESIS' THEN '论文文档' WHEN 'ARCHIVE' THEN '文档归档' ELSE ao.doc_type END AS doc_type_label, ao.round_no, ao.reviewer_id, ru.real_name AS reviewer_name, ao.score, ao.comment, ao.file_id, df.original_name AS file_name, df.file_size, df.mime_type, ao.status, CASE ao.status WHEN 'SUBMITTED' THEN '待处理' WHEN 'PASSED' THEN '已通过' WHEN 'FAILED' THEN '已驳回' ELSE ao.status END AS status_label, ao.create_time, ao.update_time, ps.student_id, su.real_name AS student_name, su.student_no, pt.topic_name, ps.custom_topic_name, ps.is_custom_topic, ps.teacher_id, tu.real_name AS teacher_name, ps.campus_name, ps.academic_year FROM approval_opinion ao INNER JOIN project_selection ps ON ao.selection_id = ps.selection_id AND ps.is_deleted = 0 INNER JOIN sys_user su ON ps.student_id = su.user_id AND su.is_deleted = 0 LEFT JOIN sys_user ru ON ao.reviewer_id = ru.user_id AND ru.is_deleted = 0 LEFT JOIN project_topic pt ON pt.topic_id = ps.topic_id AND pt.is_deleted = 0 LEFT JOIN sys_user tu ON ps.teacher_id = tu.user_id AND tu.is_deleted = 0 LEFT JOIN doc_file df ON ao.file_id = df.file_id AND df.is_deleted = 0 WHERE ao.is_deleted = 0
AND ps.campus_name = #{campusName}
AND ps.academic_year = #{academicYear}
AND (su.real_name LIKE CONCAT('%', #{keyword}, '%') OR su.student_no LIKE CONCAT('%', #{keyword}, '%') OR pt.topic_name LIKE CONCAT('%', #{keyword}, '%') OR ps.custom_topic_name LIKE CONCAT('%', #{keyword}, '%'))
AND ao.status = #{status}
AND ao.doc_type = #{docType}
ORDER BY ao.create_time DESC LIMIT #{offset}, #{limit}

